-- ============================================================================
-- Quiz Seed: Numbers — Part 3 (Chapters 21–30)
-- 3 difficulties × 10 chapters = 160 total questions
--   kids:   3 per chapter  = 30
--   teens:  5 per chapter  = 50
--   adults: 8 per chapter  = 80
-- ============================================================================

-- ═══ Numbers Chapter 21 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 21, 'kids', 1, 'What did God send to bite the people when they complained against Him?', 'Fiery serpents', 'Hornets', 'Scorpions', 'Locusts', 'a', 'Numbers 21:6 — "And the LORD sent fiery serpents among the people, and they bit the people."'),
('Numbers', 21, 'kids', 2, 'What did Moses make and put on a pole so that anyone who looked at it would be healed?', 'A serpent of brass', 'A golden calf', 'A wooden cross', 'A silver staff', 'a', 'Numbers 21:9 — "And Moses made a serpent of brass, and put it upon a pole, and it came to pass, that if a serpent had bitten any man, when he beheld the serpent of brass, he lived."'),
('Numbers', 21, 'kids', 3, 'Who did Israel defeat after singing a song about a well?', 'Sihon, king of the Amorites', 'Pharaoh of Egypt', 'The king of Arad', 'Goliath the giant', 'a', 'Numbers 21:21-24 — After the well song, Israel defeated Sihon king of the Amorites and took his land.');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 21, 'teens', 1, 'Why did God send the fiery serpents among the people of Israel?', 'The people spoke against God and against Moses', 'The people worshipped an idol', 'The people refused to fight their enemies', 'The people broke the Sabbath', 'a', 'Numbers 21:5-6 — "And the people spake against God, and against Moses...And the LORD sent fiery serpents among the people."'),
('Numbers', 21, 'teens', 2, 'What was the name of the Amorite king whose land Israel took after defeating him?', 'Sihon', 'Og', 'Balak', 'Arad', 'a', 'Numbers 21:21 — "And Israel sent messengers unto Sihon king of the Amorites."'),
('Numbers', 21, 'teens', 3, 'What happened to Israel when they defeated Og, king of Bashan?', 'They took possession of his land', 'They made a peace treaty with him', 'They drove him into the wilderness', 'They took him as a prisoner', 'a', 'Numbers 21:35 — "They smote him, and his sons, and all his people, until there was none left him alive: and they possessed his land."'),
('Numbers', 21, 'teens', 4, 'What did the Israelites sing about in the song recorded in Numbers 21?', 'A well that sprang up by the word of the Lord', 'The defeat of their enemies', 'The manna from heaven', 'The pillar of cloud and fire', 'a', 'Numbers 21:17 — "Then Israel sang this song, Spring up, O well; sing ye unto it."'),
('Numbers', 21, 'teens', 5, 'From which direction did the king of Arad attack Israel?', 'The south', 'The north', 'The east', 'The west', 'a', 'Numbers 21:1 — "And when king Arad the Canaanite, which dwelt in the south, heard tell that Israel came by the way of the spies."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 21, 'adults', 1, 'What vow did Israel make to the LORD when threatened by the king of Arad?', 'To utterly destroy the Canaanite cities if God delivered them', 'To build an altar to the LORD', 'To offer a great sacrifice', 'To fast for seven days', 'a', 'Numbers 21:2 — "And Israel vowed a vow unto the LORD, and said, If thou wilt indeed deliver this people into my hand, then I will utterly destroy their cities."'),
('Numbers', 21, 'adults', 2, 'What does Jesus cite in John 3:14 as a type of His own crucifixion?', 'Moses lifting up the serpent in the wilderness', 'The burning bush', 'The pillar of fire', 'The manna from heaven', 'a', 'John 3:14 — "And as Moses lifted up the serpent in the wilderness, even so must the Son of man be lifted up." This refers to Numbers 21:8-9.'),
('Numbers', 21, 'adults', 3, 'What is the name of the place where the people spoke against God and received the fiery serpents?', 'By mount Hor, to compass the land of Edom', 'The wilderness of Sin', 'Kadesh-barnea', 'Rephidim', 'a', 'Numbers 21:4 — "And they journeyed from mount Hor by the way of the Red sea, to compass the land of Edom: and the soul of the people was much discouraged."'),
('Numbers', 21, 'adults', 4, 'What were the people complaining about when the fiery serpents were sent?', 'There is no bread and no water, and our soul loatheth this light bread', 'They had no shoes for their feet', 'Moses had taken too much authority', 'Their enemies were too many to defeat', 'a', 'Numbers 21:5 — "Our soul loatheth this light bread" refers to the manna, showing ingratitude for God''s miraculous provision.'),
('Numbers', 21, 'adults', 5, 'What does the Hebrew name "Hormah" mean, and how was it applied in Numbers 21?', 'Utter destruction, for Israel utterly destroyed Arad', 'Holy place, where Israel worshipped', 'Victory, for the battle was won', 'Bitter waters, for the people wept there', 'a', 'Numbers 21:3 — "And the LORD hearkened to the voice of Israel...and he called the name of the place Hormah," meaning utter destruction or a devoted thing.'),
('Numbers', 21, 'adults', 6, 'What was the name of the book quoted in Numbers 21 regarding the wars of Israel?', 'The book of the wars of the LORD', 'The book of Jasher', 'The annals of the kings', 'The record of Moses', 'a', 'Numbers 21:14 — "Wherefore it is said in the book of the wars of the LORD, What he did in the Red sea, and in the brooks of Arnon."'),
('Numbers', 21, 'adults', 7, 'What happened to the city of Heshbon, formerly ruled by the Moabites, before Sihon took it?', 'It had been taken by Sihon from the king of Moab', 'It had been built by the Israelites themselves', 'It had burned down in a great fire', 'It had been abandoned for forty years', 'a', 'Numbers 21:26 — "For Heshbon was the city of Sihon the king of the Amorites, who had fought against the former king of Moab, and taken all his land out of his hand."'),
('Numbers', 21, 'adults', 8, 'What is the theological significance of the brass serpent as interpreted in 1 Corinthians 10:9 and John 3:14?', 'It is a type of Christ crucified — those who look in faith are saved from death', 'It showed Moses had power over serpents', 'It was a permanent symbol of Israel''s guilt', 'It proved that metal could ward off evil spirits', 'a', 'The brass serpent points forward to Christ''s crucifixion (John 3:14). Paul warns against tempting Christ as Israel did, referencing this event (1 Corinthians 10:9).');

-- ═══ Numbers Chapter 22 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 22, 'kids', 1, 'Who was the king that was afraid of Israel and wanted to curse them?', 'Balak, king of Moab', 'Pharaoh of Egypt', 'Sihon, king of the Amorites', 'Og, king of Bashan', 'a', 'Numbers 22:2-3 — "And Balak the son of Zippor saw all that Israel had done...And Moab was sore afraid of the people."'),
('Numbers', 22, 'kids', 2, 'What miracle happened with Balaam''s donkey?', 'It flew through the air', 'It spoke to Balaam', 'It carried a hundred men', 'It walked on water', 'a', 'Numbers 22:28 — "And the LORD opened the mouth of the ass, and she said unto Balaam, What have I done unto thee, that thou hast smitten me these three times?"'),
('Numbers', 22, 'kids', 3, 'What did the angel of the LORD have in his hand when he stood in the road?', 'A drawn sword', 'A golden staff', 'A burning torch', 'A scroll', 'a', 'Numbers 22:23 — "And the ass saw the angel of the LORD standing in the way, and his sword drawn in his hand."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 22, 'teens', 1, 'Why did Balak want Balaam to curse Israel?', 'Because Israel was too mighty for him and he hoped a curse would help him defeat them', 'Because Balaam was an enemy of Israel', 'Because the LORD told Balak to curse them', 'Because Israel had stolen his land', 'a', 'Numbers 22:6 — "For I wot that he whom thou blessest is blessed, and he whom thou cursest is cursed."'),
('Numbers', 22, 'teens', 2, 'What did God tell Balaam the first time the messengers came to him?', 'Thou shalt not go with them; thou shalt not curse the people: for they are blessed', 'He could go if he wanted', 'He should curse Israel for their sins', 'He should give the messengers a message for Balak', 'a', 'Numbers 22:12 — "And God said unto Balaam, Thou shalt not go with them; thou shalt not curse the people: for they are blessed."'),
('Numbers', 22, 'teens', 3, 'Why did the donkey turn aside from the road three times?', 'She was tired and wanted to rest', 'She saw the angel of the LORD blocking the way', 'She was frightened by a loud noise', 'She smelled water nearby', 'a', 'Numbers 22:27 — "And when the ass saw the angel of the LORD, she fell down under Balaam."'),
('Numbers', 22, 'teens', 4, 'What did the angel of the LORD tell Balaam about his mission to curse Israel?', 'Only speak the word that I shall speak unto thee', 'He had permission to curse Israel once', 'He must return home immediately', 'He should bless Balak instead', 'a', 'Numbers 22:35 — "Go with the men: but only the word that I shall speak unto thee, that thou shalt speak."'),
('Numbers', 22, 'teens', 5, 'How many times did Balaam strike his donkey before the angel spoke to him?', 'Three times', 'Once', 'Five times', 'Seven times', 'a', 'Numbers 22:28 — "And the LORD opened the mouth of the ass, and she said...that thou hast smitten me these three times?"');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 22, 'adults', 1, 'What title does Balaam hold, and what does this reveal about him spiritually?', 'A diviner and prophet-for-hire, showing the existence of pagan spiritualism outside Israel', 'A holy man of God from the tribe of Levi', 'A prophet who only served the LORD', 'A priest of the Canaanite gods', 'a', 'Numbers 22:7 — "The elders of Moab and the elders of Midian departed with the rewards of divination in their hand." Balaam practiced divination, a form of pagan sorcery.'),
('Numbers', 22, 'adults', 2, 'What does the phrase "the LORD opened the mouth of the ass" in Numbers 22:28 reveal about divine sovereignty?', 'God can use any creature or means to communicate His will and rebuke sin', 'Donkeys have a hidden intelligence', 'Balaam was imagining the conversation', 'God was mocking Balaam for his greed', 'a', 'Numbers 22:28 demonstrates God''s absolute sovereignty over creation — He can speak through any means to accomplish His purposes and correct those who oppose Him.'),
('Numbers', 22, 'adults', 3, 'What had Balaam''s donkey done for him previously that he failed to acknowledge?', 'She was a faithful servant who had never failed him before', 'She had saved his life from the sword of the angel', 'She had carried him through many battles', 'She had warned him about his enemies', 'a', 'Numbers 22:30 — "Am not I thine ass, upon which thou hast ridden ever since I was thine unto this day? was I ever wont to do so unto thee?" The donkey''s faithful service contrasts with Balaam''s hardened heart.'),
('Numbers', 22, 'adults', 4, 'What was Balaam''s sin according to 2 Peter 2:15?', 'He loved the wages of unrighteousness', 'He denied the power of God', 'He led Israel into idolatry', 'He cursed the people of God', 'a', '2 Peter 2:15 — "Which have forsaken the right way, and are gone astray, following the way of Balaam the son of Bosor, who loved the wages of unrighteousness."'),
('Numbers', 22, 'adults', 5, 'What does the angel''s statement "thy way is perverse before me" reveal about God''s view of Balaam''s journey?', 'God considered Balaam''s heart corrupt even though He permitted the journey', 'God was pleased Balaam came', 'Balaam had taken the wrong road', 'The donkey had led Balaam astray', 'a', 'Numbers 22:32 — "Thy way is perverse before me" shows that God''s permission did not equal approval; He discerned Balaam''s greedy motives.'),
('Numbers', 22, 'adults', 6, 'How is Balaam referenced in Jude 1:11 as a warning to false teachers?', 'They ran greedily after the error of Balaam for reward', 'They followed the prophecies of Balaam', 'They rejected the teaching of Balaam', 'They suffered the same fate as Balaam''s donkey', 'a', 'Jude 1:11 — "Woe unto them! for...they ran greedily after the error of Balaam for reward." False teachers are compared to Balaam''s mercenary spirituality.'),
('Numbers', 22, 'adults', 7, 'What does Balak''s message to Balaam imply about how he viewed spiritual power?', 'He believed blessing and cursing were transactional spiritual powers that could be purchased', 'He was a devoted servant of the LORD', 'He understood that Israel''s God alone was supreme', 'He was testing whether Balaam was truly a prophet', 'a', 'Numbers 22:6 — Balak sent "rewards of divination," treating prophetic power as a commodity — a view the LORD directly opposed through the entire Balaam narrative.'),
('Numbers', 22, 'adults', 8, 'What does Balaam''s offer to "do what the LORD says" reveal about his spiritual state?', 'Outward compliance mixed with inward covetousness — a form of double-mindedness', 'Complete surrender to God''s will', 'Sincere repentance and faith', 'A test of the LORD''s patience', 'a', 'Numbers 22:18 — Balaam says he cannot go beyond the LORD, yet he keeps asking God again (v.19). This pattern of outward compliance masking greed is condemned in 2 Peter 2:15.');

-- ═══ Numbers Chapter 23 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 23, 'kids', 1, 'What did Balaam keep doing when he tried to curse Israel?', 'He blessed them instead', 'He ran away in fear', 'He fell asleep', 'He forgot the words', 'a', 'Numbers 23:11 — "And Balak said unto Balaam, What hast thou done unto me? I took thee to curse mine enemies, and, behold, thou hast blessed them altogether."'),
('Numbers', 23, 'kids', 2, 'What important truth did Balaam say about God — that He is not like a person who tells lies?', 'God is not a man that he should lie', 'God is too far away to care', 'God forgets His promises sometimes', 'God changes His mind often', 'a', 'Numbers 23:19 — "God is not a man, that he should lie; neither the son of man, that he should repent."'),
('Numbers', 23, 'kids', 3, 'How many altars did Balaam ask Balak to build each time for the offerings?', 'Seven altars', 'Three altars', 'Twelve altars', 'One altar', 'a', 'Numbers 23:1 — "Build me here seven altars, and prepare me here seven oxen and seven rams."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 23, 'teens', 1, 'What did Balaam say he saw from the top of the rocks when he looked at Israel?', 'A people dwelling alone, not reckoned among the nations', 'A great army marching to war', 'A people wandering in the wilderness', 'A camp of sinners and rebels', 'a', 'Numbers 23:9 — "For from the top of the rocks I see him, and from the hills I behold him: lo, the people shall dwell alone, and shall not be reckoned among the nations."'),
('Numbers', 23, 'teens', 2, 'What famous prayer did Balaam pray in his first oracle about dying?', 'Let me die the death of the righteous, and let my last end be like his', 'Let me live as long as the stars of heaven', 'Let me return to my own people in peace', 'Let me be buried in the land of Israel', 'a', 'Numbers 23:10 — "Let me die the death of the righteous, and let my last end be like his!"'),
('Numbers', 23, 'teens', 3, 'Why could Balaam not curse Israel according to his second oracle?', 'He hath not beheld iniquity in Jacob, neither seen perverseness in Israel', 'Israel had not sinned yet', 'Balak had not paid him enough', 'God had not spoken to him clearly', 'a', 'Numbers 23:21 — "He hath not beheld iniquity in Jacob, neither hath he seen perverseness in Israel: the LORD his God is with him."'),
('Numbers', 23, 'teens', 4, 'What does Balaam''s second oracle declare that God has brought out of Egypt?', 'Israel, with the strength of a wild ox', 'A great multitude of slaves now set free', 'Twelve tribes ready for battle', 'The tabernacle and all its furnishings', 'a', 'Numbers 23:22 — "God brought them out of Egypt; he hath as it were the strength of an unicorn." The unicorn (re''em) refers to the wild ox, a symbol of unstoppable power.'),
('Numbers', 23, 'teens', 5, 'How many times did Balak try to have Balaam curse Israel in this chapter?', 'Twice', 'Once', 'Three times', 'Four times', 'a', 'In Numbers 23, Balak takes Balaam to two different locations — Bamoth-baal (v.14) and the top of Peor (v.28 begins ch.23/24 transition) — and receives two blessings instead of curses.');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 23, 'adults', 1, 'What does the statement "God is not a man, that he should lie...hath he said, and shall he not do it?" establish theologically?', 'The immutability and veracity of God — His word is absolutely reliable and cannot be reversed', 'God is superior to men in intelligence', 'Balaam was predicting the future', 'God would not allow Israel to sin', 'a', 'Numbers 23:19 — This verse is foundational to the doctrine of divine immutability and inerrancy, showing God''s promises are unconditionally reliable.'),
('Numbers', 23, 'adults', 2, 'What is the theological significance of "the LORD his God is with him, and the shout of a king is among them" in Numbers 23:21?', 'It anticipates the messianic kingship dwelling among God''s covenant people', 'It means Israel has elected a human king already', 'It refers to Moses as the king of Israel', 'It was a compliment to Balak about his kingdom', 'a', 'Numbers 23:21 — The "shout of a king" (teru''ah melek) in Israel''s midst points to the LORD''s sovereign kingship dwelling among His people, a theme culminating in Christ Emmanuel (God with us).'),
('Numbers', 23, 'adults', 3, 'What animal simile is used in Numbers 23:22 for God''s power, and what Hebrew word underlies it?', 'The re''em (wild ox), conveying irresistible, untameable divine power', 'The lion, representing royal authority', 'The eagle, representing swiftness', 'The bear, representing God''s protective anger', 'a', 'Numbers 23:22 — "He hath as it were the strength of an unicorn" (KJV). The Hebrew re''em is a wild ox, symbol of raw, untameable power.'),
('Numbers', 23, 'adults', 4, 'What does the phrase "there is no enchantment against Jacob, neither any divination against Israel" (23:23) teach about spiritual warfare?', 'No occult power can override God''s covenantal protection of His people', 'Magic does not exist in the Bible', 'Balaam had no real spiritual power', 'Israel was immune to temptation', 'a', 'Numbers 23:23 — This verse is a cornerstone text showing that when God has blessed a people, no sorcery or divination can reverse or undo His declared blessing.'),
('Numbers', 23, 'adults', 5, 'Why did Balak take Balaam to a different high place each time?', 'He hoped a different vantage point would allow Balaam to see only part of Israel and thus curse them', 'He wanted Balaam to enjoy the scenery', 'Each hill had a different idol that might help', 'He was testing Balaam''s loyalty', 'a', 'Numbers 23:13 — "Come, I pray thee, with me unto another place...thou shalt see but the utmost part of them, and shalt not see them all." Balak hoped a partial view would break the blessing.'),
('Numbers', 23, 'adults', 6, 'What do Balaam''s repeated blessings demonstrate about the Abrahamic covenant?', 'God''s promise to bless those who bless Abraham''s seed and curse those who curse them (Genesis 12:3) cannot be overturned', 'The covenant had already expired', 'Balaam was a member of the covenant community', 'Balak was secretly a believer in the LORD', 'a', 'Numbers 23 illustrates Genesis 12:3 in action — Balak tried to curse Abraham''s descendants but found God''s covenantal protection entirely invincible.'),
('Numbers', 23, 'adults', 7, 'What is the literary structure of Balaam''s first oracle in Numbers 23:7-10?', 'A taunt poem turned blessing: invitation to curse, declaration of impossibility, praise of Israel''s uniqueness, personal longing', 'A simple narrative of events', 'A hymn of praise to the LORD alone', 'A legal contract between Balak and Balaam', 'a', 'Numbers 23:7-10 follows a classic Hebrew oracle structure: the messenger formula (v.7), the impossibility of cursing (v.8), the uniqueness of Israel (v.9), and Balaam''s personal longing (v.10).'),
('Numbers', 23, 'adults', 8, 'What does the New Testament use the Balaam narrative to warn against, and in which passages?', 'Mercenary ministry and false teaching — 2 Peter 2:15, Jude 1:11, and Revelation 2:14', 'Avoiding all contact with pagans', 'The danger of speaking in public', 'Building too many altars', 'a', '2 Peter 2:15, Jude 1:11, and Revelation 2:14 all reference Balaam as a type of false teachers who corrupt God''s people for financial gain, showing how the NT uses the Numbers narrative as a sustained warning.');

-- ═══ Numbers Chapter 24 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 24, 'kids', 1, 'What beautiful image did Balaam use to describe Israel''s tents and gardens?', 'As valleys and gardens by the river side', 'As cities of gold on the hills', 'As a great forest full of trees', 'As white clouds in the sky', 'a', 'Numbers 24:5-6 — "How goodly are thy tents, O Jacob, and thy tabernacles, O Israel! As the valleys are they spread forth, as gardens by the river''s side."'),
('Numbers', 24, 'kids', 2, 'What famous object did Balaam say would come out of Jacob in a great prophecy?', 'A Star', 'A river', 'A mountain', 'A rainbow', 'a', 'Numbers 24:17 — "There shall come a Star out of Jacob, and a Sceptre shall rise out of Israel."'),
('Numbers', 24, 'kids', 3, 'What did Balak do when he was angry that Balaam kept blessing Israel?', 'He clapped his hands in anger and told Balaam to go home', 'He threw Balaam into prison', 'He tried to curse Israel himself', 'He attacked Balaam with a sword', 'a', 'Numbers 24:10 — "And Balak''s anger was kindled against Balaam, and he smote his hands together."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 24, 'teens', 1, 'What does Balaam say about himself as he begins his third oracle?', 'He is the man whose eyes are open, who heard the words of God and saw the vision of the Almighty', 'He is the wisest man in all the east', 'He is an unwilling prophet who wished to go home', 'He is a servant of Balak the king', 'a', 'Numbers 24:3-4 — "The man whose eyes are open hath said...which heard the words of God, which saw the vision of the Almighty, falling into a trance, but having his eyes open."'),
('Numbers', 24, 'teens', 2, 'What natural image does Balaam use to compare Israel''s water supply and greatness?', 'Water shall flow from his buckets and his seed shall be in many waters', 'A great river flowing to the sea', 'Springs of water in the desert', 'Rivers of living water flowing from the rock', 'a', 'Numbers 24:7 — "He shall pour the water out of his buckets, and his seed shall be in many waters."'),
('Numbers', 24, 'teens', 3, 'In the Messianic prophecy of Numbers 24:17, what two symbols represent the coming ruler from Israel?', 'A Star and a Sceptre', 'A crown and a sword', 'A lion and an eagle', 'Fire and a mountain', 'a', 'Numbers 24:17 — "There shall come a Star out of Jacob, and a Sceptre shall rise out of Israel, and shall smite the corners of Moab."'),
('Numbers', 24, 'teens', 4, 'Which nation does Balaam declare will be a servant of Israel in his fourth oracle?', 'Edom and Seir', 'Egypt and Babylon', 'Moab and Ammon', 'Canaan and Philistia', 'a', 'Numbers 24:18 — "And Edom shall be a possession, Seir also shall be a possession for his enemies; and Israel shall do valiantly."'),
('Numbers', 24, 'teens', 5, 'How does the Spirit of God come upon Balaam as described in Numbers 24:2?', 'The Spirit of God came upon him', 'An angel spoke in his ear', 'He heard a voice from the cloud', 'A dream came upon him at night', 'a', 'Numbers 24:2 — "And Balaam lifted up his eyes, and he saw Israel abiding in his tents according to their tribes; and the spirit of God came upon him."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 24, 'adults', 1, 'How is the Star prophecy of Numbers 24:17 interpreted in the New Testament and early church?', 'As a Messianic prophecy fulfilled in Jesus Christ, the bright and morning star (Revelation 22:16)', 'As a reference to Julius Caesar', 'As describing a literal astronomical event only', 'As the angel that appeared to Balaam', 'a', 'Revelation 22:16 — "I am...the bright and morning star." Early church fathers and the Magi''s visit (Matthew 2:2) connect Numbers 24:17 to the birth of Christ.'),
('Numbers', 24, 'adults', 2, 'What Hebrew term underlies "Almighty" in Numbers 24:4 and what does it convey?', 'Shaddai, meaning the all-sufficient, all-powerful God', 'Elohim, meaning the God of the covenant', 'Yahweh, meaning the self-existent one', 'Adonai, meaning the Lord and Master', 'a', 'Numbers 24:4 — "The vision of the Almighty" uses Shaddai (El Shaddai), a name for God emphasizing His all-sufficiency and overwhelming power, often used in patriarchal contexts.'),
('Numbers', 24, 'adults', 3, 'What does Balaam''s statement "falling into a trance, but having his eyes open" (24:4) describe?', 'An ecstatic prophetic state where he received genuine divine revelation', 'A literal physical illness', 'A form of deception to impress Balak', 'Sleep accompanied by dream visions', 'a', 'Numbers 24:4 describes a naphel (falling) trance with open eyes — an authentic prophetic state (machazeh), similar to the experiences of Ezekiel and John on Patmos.'),
('Numbers', 24, 'adults', 4, 'What specific nations does Balaam prophesy against at the end of chapter 24?', 'Amalek, the Kenites, Asshur, and Eber', 'Egypt, Babylon, Persia, and Greece', 'Moab, Ammon, Edom, and Philistia', 'Syria, Lebanon, Arabia, and Ethiopia', 'a', 'Numbers 24:20-24 — Balaam delivers oracles against Amalek (first of the nations but ending in destruction), the Kenites, and ships from Chittim afflicting Asshur and Eber.'),
('Numbers', 24, 'adults', 5, 'What does Balaam say about Amalek, and what is its long-term prophetic significance?', 'Amalek was the first of the nations but his latter end shall be that he perish for ever — fulfilled in 1 Samuel 15 and Esther', 'Amalek would become the greatest of all nations', 'Amalek would be absorbed into Israel peacefully', 'Amalek was already destroyed in Balaam''s day', 'a', 'Numbers 24:20 — "Amalek was the first of the nations; but his latter end shall be that he perish for ever." This was progressively fulfilled through Saul (1 Samuel 15) and finally in Esther''s day.'),
('Numbers', 24, 'adults', 6, 'How does the image of Israel as a lion in Numbers 24:9 echo the earlier blessing of Jacob in Genesis 49?', 'Both use lion imagery for Israel''s dominance and the promise that those who bless Israel are blessed', 'They are unrelated passages using the same coincidental metaphor', 'The lion refers to the tribe of Dan in both passages', 'Genesis 49 uses a wolf image, not a lion', 'a', 'Numbers 24:9 — "He couched, he lay down as a lion...Blessed is he that blesseth thee" echoes Genesis 49:9 (Judah as a lion) and 12:3, uniting the lion-covenant imagery.'),
('Numbers', 24, 'adults', 7, 'What distinction marks Balaam''s third and fourth oracles compared to the first two?', 'He ceased seeking omens and spoke purely by the Spirit of God', 'He used more altars and more sacrifices', 'He spoke from a higher mountain giving a wider view', 'He received payment before speaking', 'a', 'Numbers 24:1 — "He went not, as at other times, to seek for enchantments" — a contrast showing Balaam abandoned his divination methods and the Spirit moved freely on him.'),
('Numbers', 24, 'adults', 8, 'The "Sceptre" in Numbers 24:17 uses the Hebrew shebet — how does this word connect to the ruling prophecy of Genesis 49:10?', 'Both use shebet (sceptre/rod/tribe) to point to a ruler from Judah/Israel whose kingdom will be supreme', 'It refers to Moses'' staff used in the wilderness', 'It describes the tribe of Levi''s priestly authority', 'It refers to the ark of the covenant', 'a', 'Genesis 49:10 — "The sceptre shall not depart from Judah." Numbers 24:17 uses the same Hebrew word shebet, linking Balaam''s oracle to the Davidic/Messianic lineage promise.');

-- ═══ Numbers Chapter 25 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 25, 'kids', 1, 'With whom did the Israelites commit sin that made God very angry?', 'The daughters of Moab', 'The women of Egypt', 'The women of Canaan', 'The people of Amalek', 'a', 'Numbers 25:1 — "And Israel abode in Shittim, and the people began to commit whoredom with the daughters of Moab."'),
('Numbers', 25, 'kids', 2, 'What did Phinehas do to stop the plague God had sent?', 'He took a javelin and thrust it through a man and woman who were sinning', 'He prayed all night for the people', 'He built an altar and offered sacrifices', 'He led the people in worship songs', 'a', 'Numbers 25:7-8 — "And when Phinehas...saw it, he rose up from among the congregation, and took a javelin in his hand; and he went after the man of Israel into the tent, and thrust both of them through."'),
('Numbers', 25, 'kids', 3, 'How many people died in the plague that God sent because of Israel''s sin?', 'Twenty and four thousand', 'Six hundred thousand', 'Three thousand', 'One thousand', 'a', 'Numbers 25:9 — "And those that died in the plague were twenty and four thousand."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 25, 'teens', 1, 'What false god did the Israelites begin to worship when they joined themselves to the Moabite women?', 'Baal-peor', 'Molech', 'Dagon', 'Chemosh', 'a', 'Numbers 25:3 — "And Israel joined himself unto Baal-peor: and the anger of the LORD was kindled against Israel."'),
('Numbers', 25, 'teens', 2, 'What did God command Moses to do to the leaders of Israel because of the sin at Baal-peor?', 'Hang them up before the LORD against the sun', 'Banish them from the camp', 'Put them in prison', 'Make them offer extra sacrifices', 'a', 'Numbers 25:4 — "And the LORD said unto Moses, Take all the heads of the people, and hang them up before the LORD against the sun, that the fierce anger of the LORD may be turned away."'),
('Numbers', 25, 'teens', 3, 'What special covenant did God make with Phinehas because of his zeal?', 'The covenant of an everlasting priesthood', 'The covenant of the promised land', 'The covenant of peace with Moab', 'The covenant of kingship for his family', 'a', 'Numbers 25:12-13 — "Behold, I give unto him my covenant of peace: And he shall have it, and his seed after him, even the covenant of an everlasting priesthood."'),
('Numbers', 25, 'teens', 4, 'What tribe did the Israelite man who sinned with the Midianite woman belong to?', 'Simeon', 'Judah', 'Reuben', 'Levi', 'a', 'Numbers 25:14 — "Now the name of the Israelite that was slain...was Zimri, the son of Salu, a prince of a chief house among the Simeonites."'),
('Numbers', 25, 'teens', 5, 'What did God command Moses to do to the Midianites because of what they did at Peor?', 'Vex them and smite them', 'Make peace with them', 'Marry their daughters', 'Trade with them peacefully', 'a', 'Numbers 25:17 — "Vex the Midianites, and smite them: For they vex you with their wiles, wherewith they have beguiled you in the matter of Peor."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 25, 'adults', 1, 'How does Revelation 2:14 connect the sin at Baal-peor to Balaam''s strategy?', 'Balaam taught Balak to cast a stumblingblock before Israel by enticing them to fornication and idolatry', 'Balaam directly led the women of Moab to seduce Israel', 'Baal-peor worship began independently of Balaam', 'Balaam later repented and warned Israel of the danger', 'a', 'Revelation 2:14 — "Thou hast there them that hold the doctrine of Balaam, who taught Balak to cast a stumblingblock before the children of Israel." Numbers 25 fulfils Balaam''s counsel.'),
('Numbers', 25, 'adults', 2, 'What is the theological significance of Phinehas'' act of zeal according to Psalm 106:30-31?', 'It was counted unto him for righteousness unto all generations for ever', 'It showed that violence is always justified against sinners', 'It earned him the title of king of Israel', 'It ended all future idolatry in Israel', 'a', 'Psalm 106:30-31 — "Then stood up Phinehas, and executed judgment: and so the plague was stayed. And that was counted unto him for righteousness unto all generations for evermore."'),
('Numbers', 25, 'adults', 3, 'What does the phrase "he was zealous for his God" (25:13) reveal about the basis for Phinehas'' action?', 'His act was motivated by covenant loyalty and righteous indignation against sin, not personal anger', 'He was angry at the man personally', 'He acted to gain honour for himself', 'He was enforcing a new law Moses had just given', 'a', 'Numbers 25:13 — "Because he was zealous for his God, and made an atonement for the children of Israel." Phinehas'' act mirrored God''s own jealousy (qin''ah) for His holiness.'),
('Numbers', 25, 'adults', 4, 'How does Paul use the death toll at Baal-peor in 1 Corinthians 10:8 as a New Testament warning?', 'He warns against fornication, citing that twenty and three thousand fell in one day', 'He praises Israel for repenting after the plague', 'He uses it to argue for strict dietary laws', 'He cites it as proof of God''s patience with sinners', 'a', '1 Corinthians 10:8 — "Neither let us commit fornication, as some of them committed, and fell in one day three and twenty thousand." Paul uses this event as a direct warning against sexual immorality.'),
('Numbers', 25, 'adults', 5, 'What is the name of the Midianite woman killed by Phinehas, and what was her social standing?', 'Cozbi the daughter of Zur, a head of a chief house in Midian', 'An unnamed servant of the Midianite king', 'A priestess of Baal-peor', 'A daughter of the king of Moab', 'a', 'Numbers 25:15 — "And the name of the Midianitish woman that was slain was Cozbi, the daughter of Zur; he was head over a people, and of a chief house in Midian."'),
('Numbers', 25, 'adults', 6, 'What does the phrase "made an atonement for the children of Israel" (25:13) applied to Phinehas'' act indicate theologically?', 'That the execution of judgment on unrepentant sinners can function as an act of atonement that satisfies God''s wrath', 'That Phinehas had priestly power to forgive sins', 'That animal sacrifice was no longer needed', 'That God approved of all acts of violence in His name', 'a', 'Numbers 25:13 — "He made an atonement" (kaphar) for Israel. The act of righteous judgment removed the defilement, satisfying divine holiness and stopping the plague.'),
('Numbers', 25, 'adults', 7, 'What does the sin at Baal-peor reveal about the connection between sexual immorality and idolatry in Scripture?', 'They are inseparably linked — pagan worship characteristically used sexual immorality as religious rite', 'They are separate sins with different consequences', 'Sexual immorality was only condemned in this one instance', 'Idolatry was the minor offence and immorality the major one', 'a', 'Numbers 25:1-3 shows the pattern: "the people began to commit whoredom...and they called the people unto the sacrifices of their gods...and Israel joined himself unto Baal-peor." Paul develops this same link in Romans 1:24-25.'),
('Numbers', 25, 'adults', 8, 'What does the covenant of peace (shalom) given to Phinehas foreshadow in the broader redemptive narrative?', 'It foreshadows the Aaronic high priestly line through which atonement and peace with God would be mediated', 'It establishes Phinehas as the first king of Israel', 'It promises that war will never come to Israel', 'It is an unconditional promise that all his descendants will be righteous', 'a', 'Numbers 25:12-13 — The "covenant of peace" and "everlasting priesthood" given to Phinehas continues the Aaronic line of mediation, pointing forward to the ultimate High Priest who makes peace through His blood (Colossians 1:20).');

-- ═══ Numbers Chapter 26 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 26, 'kids', 1, 'What did God tell Moses to do with all the men of Israel after the plague?', 'Count all the congregation of Israel', 'Send them into battle immediately', 'Build a new tabernacle', 'Travel to the promised land at once', 'a', 'Numbers 26:2 — "Take the sum of all the congregation of the children of Israel, from twenty years old and upward, throughout their fathers'' house."'),
('Numbers', 26, 'kids', 2, 'Who led the second census of Israel along with Moses?', 'Eleazar the priest', 'Aaron the priest', 'Joshua the son of Nun', 'Caleb the son of Jephunneh', 'a', 'Numbers 26:3 — "And Moses and Eleazar the priest spake with them in the plains of Moab by Jordan near Jericho."'),
('Numbers', 26, 'kids', 3, 'How was the land of Canaan to be divided among the tribes?', 'By lot', 'By drawing straws', 'By fighting for it', 'By the elders deciding', 'a', 'Numbers 26:55 — "Notwithstanding the land shall be divided by lot: according to the names of the tribes of their fathers they shall inherit."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 26, 'teens', 1, 'What was the total number of men counted in the second census of Israel?', 'Six hundred thousand and a thousand seven hundred and thirty', 'Six hundred and three thousand five hundred and fifty', 'Five hundred thousand', 'Seven hundred thousand', 'a', 'Numbers 26:51 — "These were the numbered of the children of Israel, six hundred thousand and a thousand seven hundred and thirty."'),
('Numbers', 26, 'teens', 2, 'Which two men from the first census were still alive at the time of the second census?', 'Caleb and Joshua', 'Moses and Aaron', 'Phinehas and Eleazar', 'Reuben and Simeon', 'a', 'Numbers 26:65 — "For the LORD had said of them, They shall surely die in the wilderness. And there was not left a man of them, save Caleb the son of Jephunneh, and Joshua the son of Nun."'),
('Numbers', 26, 'teens', 3, 'What happened to Korah and the men who gathered with him against Moses, referenced in this chapter?', 'The earth opened her mouth and swallowed them up', 'They were driven out of the camp', 'They were struck by lightning', 'They died of the plague', 'a', 'Numbers 26:10 — "And the earth opened her mouth, and swallowed them up together with Korah, when that company died, what time the fire devoured two hundred and fifty men."'),
('Numbers', 26, 'teens', 4, 'How was the size of a tribe''s inheritance in the land to be determined?', 'To more people thou shalt give more inheritance, and to fewer less', 'All tribes received equal portions of land', 'The largest tribe chose first and took the best land', 'The priests decided how much each tribe received', 'a', 'Numbers 26:54 — "To many thou shalt give the more inheritance, and to few thou shalt give the less inheritance: to every one shall his inheritance be given according to those that were numbered of him."'),
('Numbers', 26, 'teens', 5, 'Which tribe was not counted in this census because they received no inheritance of land?', 'Levi', 'Simeon', 'Reuben', 'Dan', 'a', 'Numbers 26:62 — "And those that were numbered of them were twenty and three thousand, all males from a month old and upward: for they were not numbered among the children of Israel, because there was no inheritance given them among the children of Israel."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 26, 'adults', 1, 'What theological purpose does the second census serve in the narrative of Numbers?', 'It marks the transition to the new wilderness generation ready to inherit the land, fulfilling God''s judgment on the first generation', 'It was a military exercise to plan battle strategy', 'It showed that Israel had grown stronger than Egypt', 'It was required by Canaanite custom before entering new territory', 'a', 'Numbers 26 occurs after the first generation died (v.64-65), marking the fulfilment of God''s judgment (14:29-30) and the preparation of a new generation for conquest.'),
('Numbers', 26, 'adults', 2, 'What does the comparison of the first census (603,550 — Numbers 1:46) and the second census (601,730 — Numbers 26:51) reveal?', 'A slight decrease of about 1,820 men, showing the effect of forty years of divine judgment on the unfaithful generation', 'Israel had doubled in size through the wilderness', 'God had broken His promise to multiply Israel', 'The census numbers were rounded approximations with no theological meaning', 'a', 'The nearly identical totals (603,550 vs. 601,730) show that despite forty years of wilderness judgments and mass deaths, God preserved Israel''s strength — His covenant faithfulness sustained them.'),
('Numbers', 26, 'adults', 3, 'What is the significance of Zelophehad''s daughters being mentioned in the census record (26:33)?', 'It sets up the inheritance case in chapter 27, raising the issue of daughters inheriting when there is no male heir', 'It was a clerical error in the original census', 'It showed that women were also counted in the census', 'It proved that Zelophehad was innocent of rebellion', 'a', 'Numbers 26:33 — "And Zelophehad the son of Hepher had no sons, but daughters" — this editorial note prepares the reader for the inheritance petition in Numbers 27.'),
('Numbers', 26, 'adults', 4, 'What does the use of lot for land distribution (26:55-56) convey theologically?', 'It acknowledged God as the ultimate disposer of the land, removing human partiality from the process', 'It was a democratic method Israel preferred', 'It showed that the land was not really God''s to give', 'It was used because Moses could not decide fairly', 'a', 'Numbers 26:56 — "According to the lot shall the possession thereof be divided." The lot (goral) was a divine oracle in Israelite practice (Proverbs 16:33), acknowledging God''s sovereignty in allocating His land.'),
('Numbers', 26, 'adults', 5, 'How does the survival of Caleb and Joshua alone from the first generation fulfil the prophecy of Numbers 14:30?', 'God promised in 14:30 that only Caleb and Joshua would enter the land — the second census confirms all others died', 'The prophecy was conditional and most of the first generation survived', 'Caleb and Joshua survived by their own strength and wisdom', 'The prophecy referred to the second generation, not the first', 'a', 'Numbers 14:30 — "Doubtless ye shall not come into the land...save Caleb the son of Jephunneh, and Joshua the son of Nun." Numbers 26:65 confirms complete fulfilment.'),
('Numbers', 26, 'adults', 6, 'What is the significance of the sons of Korah not dying with their father (26:11)?', 'It shows God''s mercy extends to families — children are not condemned for a father''s rebellion', 'It proved that Korah''s sons had escaped underground', 'It was a clerical error in the census', 'It showed that the sons had repented before the judgment', 'a', 'Numbers 26:11 — "Notwithstanding the children of Korah died not." This is a remarkable statement of divine mercy and would have been of comfort to the Korahites who later wrote several Psalms (42, 44-49, 84-85, 87-88).'),
('Numbers', 26, 'adults', 7, 'How does the principle "to many...more inheritance, to few...less" (26:54) reflect distributive justice in God''s economy?', 'It ensured the land allocation was proportional to family size, making the inheritance practically viable for each tribe', 'It favoured the larger and stronger tribes', 'It contradicted the principle of equality in the law', 'It was overruled by the lot system entirely', 'a', 'Numbers 26:54 establishes a principle combining divine sovereignty (the lot) with practical equity (proportional size), showing that God''s justice is both impartial and contextually fair.'),
('Numbers', 26, 'adults', 8, 'What does the fact that the Levites were numbered separately, from a month old upward rather than from twenty, reveal about their distinct calling?', 'The Levites were not a military force but a priestly service corps — their census reflected their function, not fighting capacity', 'The Levites were considered too weak to be counted in the main census', 'Moses forgot to include them in the original count', 'Levitical families were smaller and needed a lower minimum age', 'a', 'Numbers 26:62 — The Levites were counted separately (from one month, not twenty) because they served the tabernacle, not in warfare, reflecting their distinct calling as a holy tribe devoted to God.');

-- ═══ Numbers Chapter 27 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 27, 'kids', 1, 'Whose daughters came to Moses asking for an inheritance of land?', 'The daughters of Zelophehad', 'The daughters of Aaron', 'The daughters of Caleb', 'The daughters of Moses', 'a', 'Numbers 27:1 — "Then came the daughters of Zelophehad, the son of Hepher...and these are the names of his daughters; Mahlah, Noah, and Hoglah, and Milcah, and Tirzah."'),
('Numbers', 27, 'kids', 2, 'Who did God choose to lead Israel after Moses?', 'Joshua the son of Nun', 'Caleb the son of Jephunneh', 'Eleazar the priest', 'Phinehas the son of Eleazar', 'a', 'Numbers 27:18 — "And the LORD said unto Moses, Take thee Joshua the son of Nun, a man in whom is the spirit, and lay thine hand upon him."'),
('Numbers', 27, 'kids', 3, 'Why was Moses told he would not enter the promised land?', 'Because he disobeyed at the waters of Meribah', 'Because he was too old', 'Because he had refused to lead the people', 'Because he did not finish building the tabernacle', 'a', 'Numbers 27:14 — "For ye rebelled against my commandment in the desert of Zin...to sanctify me at the water before their eyes: that is the water of Meribah in Kadesh."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 27, 'teens', 1, 'What was the legal argument of Zelophehad''s daughters for receiving their father''s inheritance?', 'Their father died in his own sin and had no sons — his name should not disappear from his family', 'They were the only surviving members of the family', 'The law required daughters to inherit before cousins', 'Moses had already promised them land', 'a', 'Numbers 27:3-4 — "Our father died in the wilderness...and had no sons. Why should the name of our father be done away from among his family, because he hath no son? Give unto us therefore a possession."'),
('Numbers', 27, 'teens', 2, 'What did God say when Moses brought the case of Zelophehad''s daughters before Him?', 'The daughters of Zelophehad speak right — thou shalt surely give them a possession of inheritance', 'He denied their request and referred the case to the elders', 'He said the existing law must stand unchanged', 'He told Moses to consult with the princes of the tribes', 'a', 'Numbers 27:7 — "The daughters of Zelophehad speak right: thou shalt surely give them a possession of an inheritance among their father''s brethren."'),
('Numbers', 27, 'teens', 3, 'What was Moses told to do before he died so that the congregation would not be without a leader?', 'Set Joshua before Eleazar the priest and the congregation, and give him a charge in their sight', 'Write down all the laws for the next leader', 'Appoint twelve judges to lead the tribes', 'Give Phinehas the authority of the high priest', 'a', 'Numbers 27:19 — "And set him before Eleazar the priest, and before all the congregation; and give him a charge in their sight."'),
('Numbers', 27, 'teens', 4, 'What inheritance law was established for cases where a man died without sons?', 'His inheritance shall pass to his daughter, then brother, then father''s brother, then nearest kinsman', 'His land returned to the LORD and was redistributed', 'The eldest son of his closest neighbor would inherit', 'The tribe''s elders would divide it equally', 'a', 'Numbers 27:8-11 establishes a hierarchy: daughter → brothers → father''s brothers → nearest kinsman, making this an early example of codified inheritance law.'),
('Numbers', 27, 'teens', 5, 'What title is given to Joshua when God describes him as the right person to succeed Moses?', 'A man in whom is the spirit', 'The greatest warrior in Israel', 'A man after God''s own heart', 'The wisest of all the judges', 'a', 'Numbers 27:18 — "And the LORD said unto Moses, Take thee Joshua the son of Nun, a man in whom is the spirit, and lay thine hand upon him."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 27, 'adults', 1, 'What is the theological significance of God upholding the daughters of Zelophehad''s claim?', 'It reveals God''s concern for equity and the preservation of family inheritance within His covenant structure', 'It showed that women had equal military roles', 'It proved that the Mosaic law could be changed by popular appeal', 'It demonstrated that Moses was too strict in applying the law', 'a', 'Numbers 27:7 — God Himself declares their request "right" (ken), showing His justice extends to the vulnerable and that the covenant land inheritance was important enough to expand protections.'),
('Numbers', 27, 'adults', 2, 'How does Joshua''s commissioning through laying on of hands (27:18-23) establish a precedent in Scripture?', 'It is one of the earliest formal acts of ordination — the transfer of authority and Spirit through symbolic imposition of hands', 'It was a purely ceremonial gesture with no spiritual meaning', 'It was the same as anointing with oil', 'It showed Moses was transferring his magical powers', 'a', 'Numbers 27:18-23 — Moses lays hands on Joshua before the priest and congregation, a formal act of ordination that becomes foundational in the NT for authorizing ministry (1 Timothy 4:14; Acts 6:6).'),
('Numbers', 27, 'adults', 3, 'What does the description of Moses approaching God about his successor as "the congregation of the LORD be not as sheep which have no shepherd" (27:17) foreshadow?', 'It foreshadows Jesus describing Himself as the Good Shepherd (John 10) and His compassion for leaderless crowds (Matthew 9:36)', 'It was a practical concern about military leadership only', 'It compared the Israelites unfavourably to sheep', 'It showed Moses doubted God would provide a leader', 'a', 'Numbers 27:17 — "That the congregation of the LORD be not as sheep which have no shepherd." Jesus uses almost identical language in Matthew 9:36 and identifies Himself as the fulfilment in John 10.'),
('Numbers', 27, 'adults', 4, 'What is the significance of Joshua needing to inquire of Eleazar the priest using the Urim for decisions (27:21)?', 'It marks a shift from the prophetic immediacy of Moses to the priestly-mediatorial structure that will characterise the judges era', 'It showed Joshua was less gifted than Moses', 'It meant Eleazar had more authority than Joshua', 'It was required because Joshua was a Gentile', 'a', 'Numbers 27:21 — "He shall stand before Eleazar the priest, who shall ask counsel for him after the judgment of Urim." Unlike Moses who spoke with God face to face (12:8), Joshua operates through priestly mediation — a significant structural change.'),
('Numbers', 27, 'adults', 5, 'What does the phrase "gathered unto his people" used for Moses (27:13) reveal about the Old Testament concept of death?', 'It implies continuation beyond death — a gathering of the person with their covenant forebears', 'It simply means burial in the family tomb', 'It was a euphemism meaning Moses would be forgotten', 'It described Moses leaving his leadership role', 'a', 'Numbers 27:13 — "Thou...shalt be gathered unto thy people, as Aaron thy brother was gathered." This phrase implies a conscious continuation and reunion with deceased forebears, reflecting OT belief in afterlife.'),
('Numbers', 27, 'adults', 6, 'What does Moses'' intercession for a successor rather than self-pity reveal about his character?', 'His primary concern was the welfare of God''s people, not his own loss of the promised land', 'He had already accepted his punishment without feeling', 'He was glad to be finished with leading Israel', 'He doubted God''s fairness but submitted anyway', 'a', 'Numbers 27:15-17 — Immediately after hearing he will die before entering Canaan, Moses prays for a successor. This selfless response reflects Moses'' servant heart, contrasting with any self-centred reaction.'),
('Numbers', 27, 'adults', 7, 'How does the inheritance legislation in Numbers 27:8-11 relate to the later institution of the kinsman-redeemer in Leviticus 25 and the book of Ruth?', 'Both laws protect family land inheritance and redemption within the covenant community, showing God''s concern for the continuity of tribal identity', 'They are entirely different laws with no connection', 'The kinsman-redeemer law superseded the Numbers 27 ruling', 'Ruth''s situation had nothing to do with inheritance', 'a', 'Numbers 27:8-11 and Leviticus 25:25-28 together form an integrated legal framework for land redemption, illustrated perfectly in Ruth 4 where Boaz acts as kinsman-redeemer to preserve Elimelech''s name and inheritance.'),
('Numbers', 27, 'adults', 8, 'Why is Joshua described as having "the spirit" (27:18) before Moses lays hands on him?', 'The spirit of leadership was already in him — Moses'' laying on of hands confirmed and authorised what God had already given', 'He received the spirit only after Moses laid hands on him', 'It refers to a special military spirit of courage', 'Moses was testing whether Joshua had the spirit', 'a', 'Numbers 27:18 — "A man in whom is the spirit." The pre-existing spirit indicates Joshua was already divinely equipped; the ordination ceremony publicly recognised and authorised his already-established calling (cf. Deuteronomy 34:9).');

-- ═══ Numbers Chapter 28 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 28, 'kids', 1, 'How many times every day were the Israelites commanded to offer a burnt offering to God?', 'Two times — morning and evening', 'Once at noon', 'Three times a day', 'Seven times a day', 'a', 'Numbers 28:3-4 — "Two lambs of the first year without spot day by day, for a continual burnt offering. The one lamb shalt thou offer in the morning, and the other lamb shalt thou offer at even."'),
('Numbers', 28, 'kids', 2, 'What special offering was added on the Sabbath day beyond the daily offering?', 'Two extra lambs and a drink offering', 'A goat for a sin offering', 'Seven bulls and seven rams', 'An offering of bread and oil', 'a', 'Numbers 28:9 — "And on the sabbath day two lambs of the first year without spot, and two tenth deals of flour for a meat offering, mingled with oil."'),
('Numbers', 28, 'kids', 3, 'What Jewish feast celebrated in the first month required eating unleavened bread for seven days?', 'The Passover and feast of unleavened bread', 'The feast of trumpets', 'The feast of tabernacles', 'The feast of firstfruits', 'a', 'Numbers 28:17 — "And in the fifteenth day of this month is the feast: seven days shall unleavened bread be eaten."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 28, 'teens', 1, 'What was the daily burnt offering called, and what did it represent about Israel''s relationship with God?', 'The continual burnt offering — tamid — representing uninterrupted consecration to God', 'The morning prayer service', 'The evening thanksgiving offering', 'The national sin offering', 'a', 'Numbers 28:3 — "A continual burnt offering" (Hebrew: olah tamid). The tamid offering symbolised Israel''s perpetual dedication to God, offered every morning and evening without interruption.'),
('Numbers', 28, 'teens', 2, 'What was offered at the beginning of every month (the new moon)?', 'Two young bullocks, one ram, and seven lambs, with a goat for a sin offering', 'Fourteen lambs and four rams', 'One bull and one lamb', 'Seven goats and seven doves', 'a', 'Numbers 28:11 — "And in the beginnings of your months ye shall offer a burnt offering unto the LORD; two young bullocks, and one ram, seven lambs of the first year without spot."'),
('Numbers', 28, 'teens', 3, 'On the first day of the Passover feast, what was commanded regarding work?', 'There shall be an holy convocation — no servile work shall be done', 'Everyone must travel to Jerusalem', 'All livestock must be rested', 'Extra offerings must be given each morning', 'a', 'Numbers 28:18 — "In the first day shall be an holy convocation; ye shall do no manner of servile work therein."'),
('Numbers', 28, 'teens', 4, 'What offering was included alongside burnt offerings as an atonement for the congregation?', 'One kid of the goats for a sin offering', 'A red heifer', 'Ten doves and ten pigeons', 'A lamb without blemish', 'a', 'Numbers 28:15 — "And one kid of the goats for a sin offering unto the LORD shall be offered, beside the continual burnt offering, and his drink offering."'),
('Numbers', 28, 'teens', 5, 'What feast was celebrated on the fiftieth day after Passover with special offerings in Numbers 28?', 'The day of firstfruits (Feast of Weeks / Pentecost)', 'The feast of tabernacles', 'The feast of trumpets', 'The day of atonement', 'a', 'Numbers 28:26 — "Also in the day of the firstfruits, when ye bring a new meat offering unto the LORD, after your weeks be out, ye shall have an holy convocation."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 28, 'adults', 1, 'What does the phrase "my bread for my sacrifices made by fire, for a sweet savour unto me" (28:2) reveal about the nature of Israel''s offerings?', 'The sacrifices were understood as a pleasing gift to God — spiritual nourishment symbolically rendered back to the One who provides all bread', 'God was physically nourished by the sacrifices', 'It was a Canaanite phrase adapted by Moses', 'The offerings were only symbolic gestures with no spiritual significance', 'a', 'Numbers 28:2 — "My bread for my sacrifices made by fire." The language of "bread" (lehem) and "sweet savour" (reyach nichoach) points to the sacrificial system as a divinely ordained means of covenantal fellowship.'),
('Numbers', 28, 'adults', 2, 'How does the tamid (continual) offering foreshadow Christ''s perpetual intercession in Hebrews 7:25?', 'As the daily offering was perpetual and uninterrupted, so Christ ever lives to make intercession for His people, providing continuous atonement', 'The tamid simply established a pattern for prayer times', 'Christ''s sacrifice is a one-time event with no ongoing element', 'The tamid offering is only relevant to Old Testament worship', 'a', 'Hebrews 7:25 — "He ever liveth to make intercession." The morning and evening tamid offerings prefigure Christ''s unceasing intercessory ministry before the Father.'),
('Numbers', 28, 'adults', 3, 'What is the theological significance of the Passover offering within the sacrificial calendar of Numbers 28?', 'It commemorated redemption from Egypt and pointed forward to Christ as the Passover Lamb (1 Corinthians 5:7)', 'It was only a historical memorial with no prophetic content', 'It celebrated the giving of the law at Sinai', 'It was the least important of the annual feasts', 'a', '1 Corinthians 5:7 — "Christ our passover is sacrificed for us." The Passover lamb of Numbers 28:16-24 is a direct type of Christ, connecting Israel''s deliverance from Egypt to spiritual deliverance from sin.'),
('Numbers', 28, 'adults', 4, 'Why does the Feast of Weeks offering in Numbers 28:26-31 gain profound New Testament significance?', 'The Holy Spirit was poured out on the day of Pentecost (the Feast of Weeks), fulfilling its prophetic function as a firstfruits of the harvest', 'It was replaced by baptism in the New Testament', 'It had no connection to the New Testament', 'It was renamed the Lord''s Supper by the apostles', 'a', 'Acts 2:1 — "And when the day of Pentecost was fully come." The Feast of Weeks (Pentecost) in Numbers 28:26 is the feast on which the Holy Spirit fell, fulfilling the firstfruits imagery.'),
('Numbers', 28, 'adults', 5, 'What does the requirement that all offerings be "without spot" or "without blemish" symbolise theologically?', 'The holiness and perfection required in approaching God, ultimately pointing to Christ the spotless Lamb (1 Peter 1:19)', 'It was a practical measure to ensure only healthy animals were used', 'It was a test of the worshipper''s wealth', 'The blemish requirement was purely ceremonial with no deeper meaning', 'a', '1 Peter 1:19 — "As of a lamb without blemish and without spot: Even the blood of Christ." The unblemished offerings throughout Numbers 28 consistently point to Christ''s perfect sacrifice.'),
('Numbers', 28, 'adults', 6, 'What does the monthly (new moon) offering reveal about God''s claim over all time?', 'God required the marking of every new month with sacrifice, consecrating all time to Him and acknowledging His lordship over the calendar', 'The new moon offering was adopted from Canaanite lunar worship', 'It was simply an agricultural calendar marker with no theological content', 'The new moon offering was only observed in the temple period', 'a', 'Numbers 28:11 — The monthly new moon offering (rosh hodesh) sanctified each month to the LORD, showing that Israel''s entire calendar was a sacred offering of time to God, not merely a natural or agricultural cycle.'),
('Numbers', 28, 'adults', 7, 'How does the structure of Numbers 28-29 (daily, weekly, monthly, annual) reflect a theology of time and worship?', 'It establishes a comprehensive liturgical calendar showing that every unit of time — day, week, month, year — is consecrated to God through sacrifice', 'It was a practical schedule to prevent over-sacrifice', 'It was modelled after Egyptian temple practices', 'It shows that some times were more sacred than others with no unifying theology', 'a', 'Numbers 28-29 presents a nested calendar: daily tamid → weekly Sabbath → monthly new moon → annual feasts. This total sanctification of time reflects God''s lordship over all creation''s rhythms.'),
('Numbers', 28, 'adults', 8, 'How does the drink offering of wine that accompanies burnt offerings in Numbers 28 connect to the New Testament Lord''s Supper?', 'Wine poured out as an offering foreshadows the blood of Christ poured out in the new covenant (Luke 22:20), linking sacrifice and drink offering', 'The drink offering was only a libation to accompany meals', 'Paul explicitly forbade the use of wine in worship', 'The drink offering has no connection to the Lord''s Supper', 'a', 'Luke 22:20 — "This cup is the new testament in my blood, which is shed for you." The wine of the drink offering (Numbers 28:7) points forward to the cup of the new covenant, both representing blood poured out in sacrifice.');

-- ═══ Numbers Chapter 29 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 29, 'kids', 1, 'What feast began on the first day of the seventh month with a special trumpet sound?', 'The feast of trumpets', 'The feast of tabernacles', 'The feast of passover', 'The feast of weeks', 'a', 'Numbers 29:1 — "And in the seventh month, on the first day of the month, ye shall have an holy convocation; ye shall do no servile work: it is a day of blowing the trumpets unto you."'),
('Numbers', 29, 'kids', 2, 'How many days did the feast of tabernacles last, starting on the fifteenth day of the seventh month?', 'Seven days', 'Three days', 'Ten days', 'Fourteen days', 'a', 'Numbers 29:12 — "And on the fifteenth day of the seventh month ye shall have an holy convocation...and ye shall keep a feast unto the LORD seven days."'),
('Numbers', 29, 'kids', 3, 'What happened to the number of bulls offered each day during the feast of tabernacles?', 'It went down by one each day', 'It doubled each day', 'It stayed the same every day', 'It went up by one each day', 'a', 'Numbers 29:13-32 — The feast of tabernacles began with thirteen bulls on the first day, twelve on the second, down to seven on the seventh day, a descending pattern unique in the sacrificial calendar.');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 29, 'teens', 1, 'On which day of the seventh month was the Day of Atonement observed?', 'The tenth day', 'The first day', 'The fifteenth day', 'The twenty-second day', 'a', 'Numbers 29:7 — "And ye shall have on the tenth day of this seventh month an holy convocation; and ye shall afflict your souls."'),
('Numbers', 29, 'teens', 2, 'What unique requirement accompanied the Day of Atonement that was not required for other feasts?', 'Afflicting your souls and doing no work at all', 'Eating only unleavened bread', 'Bringing a wave offering to the priest', 'Travelling to a designated holy site', 'a', 'Numbers 29:7 — "And ye shall have on the tenth day of this seventh month an holy convocation; and ye shall afflict your souls: ye shall not do any work therein."'),
('Numbers', 29, 'teens', 3, 'How many bulls were offered on the first day of the feast of tabernacles?', 'Thirteen young bullocks', 'Seven bulls', 'Twelve bulls', 'Ten bulls', 'a', 'Numbers 29:13 — "And ye shall offer a burnt offering, a sacrifice made by fire...thirteen young bullocks, two rams, and fourteen lambs of the first year."'),
('Numbers', 29, 'teens', 4, 'What was the total number of bulls offered over the seven days of the feast of tabernacles?', 'Seventy', 'Forty-nine', 'Eighty-four', 'Sixty', 'a', 'Numbers 29:13-32 — The bulls decreased from 13 to 7 over seven days: 13+12+11+10+9+8+7 = 70 bulls total, a number the rabbis later associated with the seventy nations of the world.'),
('Numbers', 29, 'teens', 5, 'What was the eighth day after the feast of tabernacles called, and what was it like?', 'A solemn assembly — a holy convocation with reduced offerings', 'A day of fasting and mourning', 'A day with double the normal offerings', 'A day of rest with no offerings at all', 'a', 'Numbers 29:35 — "On the eighth day ye shall have a solemn assembly: ye shall do no servile work therein." The eighth day (Shemini Atzeret) was a special sacred closing day.');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 29, 'adults', 1, 'What does the blowing of trumpets on the first day of the seventh month signify, and what is its New Testament fulfilment?', 'The summoning of God''s people to sacred assembly — fulfilled ultimately in the last trumpet that raises the dead (1 Corinthians 15:52)', 'It was a military signal to prepare for battle', 'It was purely an agricultural harvest announcement', 'The trumpet had no symbolic meaning beyond calling attention', 'a', '1 Corinthians 15:52 — "At the last trump...the dead shall be raised incorruptible." The feast of trumpets points forward to the final divine gathering of God''s people at the resurrection.'),
('Numbers', 29, 'adults', 2, 'How does the Day of Atonement in Numbers 29:7-11 connect to the theology of Hebrews 9-10?', 'The high priest''s annual entry into the Most Holy Place on Yom Kippur is fulfilled and superseded by Christ''s once-for-all entry into heaven (Hebrews 9:12)', 'The Day of Atonement was simply abolished in the New Testament', 'Hebrews 9-10 has no connection to Numbers 29', 'The Day of Atonement continued unchanged after the cross', 'a', 'Hebrews 9:12 — "Neither by the blood of goats and calves, but by his own blood he entered in once into the holy place, having obtained eternal redemption." Numbers 29:7-11 is the annual shadow; Christ is the final reality.'),
('Numbers', 29, 'adults', 3, 'What is the rabbinic interpretation of the seventy bulls offered during the feast of tabernacles, and does it find any support in the text?', 'The seventy bulls represent the seventy nations of the world — Israel interceding for all humanity, consistent with Abraham''s seventy descendants and the Table of Nations in Genesis 10', 'The seventy is only a mathematical coincidence with no theological meaning', 'The seventy represent the seventy elders of Israel', 'The total was actually sixty-eight, not seventy', 'a', 'Numbers 29:13-32 yields exactly 70 bulls (13+12+11+10+9+8+7). The rabbinic identification with Genesis 10''s 70 nations (b.Sukkah 55b) is widely accepted as a valid typological interpretation.'),
('Numbers', 29, 'adults', 4, 'What does the phrase "ye shall afflict your souls" (29:7) for the Day of Atonement indicate in terms of spiritual practice?', 'It refers to fasting and self-humiliation — externally expressing inner contrition before God on the most solemn day of the calendar', 'It required physical self-flagellation', 'It meant sacrificing one''s personal livestock', 'It was a purely ceremonial phrase with no practical requirement', 'a', 'Numbers 29:7 — "Ye shall afflict your souls" (anah nephesh) is consistently interpreted as fasting (Leviticus 23:27-32, Isaiah 58:3-5), representing the humiliation of the self before God''s holiness.'),
('Numbers', 29, 'adults', 5, 'How does the decreasing bull sequence of the feast of tabernacles (13 to 7) differ from all other feast offerings, and what might this symbolise?', 'It is the only descending sequence in the entire sacrificial calendar, possibly symbolising the intensifying focus of the feast as it builds toward the solemn eighth day', 'Every feast used a decreasing sequence', 'The decrease was due to limited livestock supply', 'It simply prevented an over-large total number of sacrifices', 'a', 'Numbers 29:13-32 — The 13-to-7 descending sequence is unique in the Mosaic calendar. Various interpreters see it as an intensification toward the solemn assembly on the eighth day, or as a decreasing earthward orientation building toward an eternal gathering.'),
('Numbers', 29, 'adults', 6, 'What is the significance of the seventh month (Tishri) as the month of the three great feasts in Numbers 29?', 'The seventh month mirrors the seventh day — a sabbatical principle applied to the year, making it the month most dedicated to divine encounter and atonement', 'The seventh month was chosen randomly by Moses', 'It corresponded to the agricultural new year only', 'The seventh month had no special holiness beyond its feasts', 'a', 'Numbers 29 concentrates three major observances in the seventh month: Trumpets (day 1), Atonement (day 10), Tabernacles (days 15-22). The sabbatical pattern (7th = holy) applies to months as it does to days and years.'),
('Numbers', 29, 'adults', 7, 'How does John 7:37-39, where Jesus cried out at the feast of tabernacles about living water, engage with the Numbers 29 sacrificial context?', 'Jesus used the water-pouring ceremony of Sukkot (derived from the tabernacles ordinances) to declare Himself the fulfilment of all the feast foreshadowed', 'Jesus was unaware of the feast''s sacrificial background', 'John 7 has no connection to Numbers 29', 'Jesus condemned the water ceremony as a pagan addition', 'a', 'John 7:37-39 — "If any man thirst, let him come unto me, and drink." Jesus'' declaration at the climactic moment of the Sukkot water-drawing ceremony points to the Spirit as the fulfilment of what the feast of tabernacles promised.'),
('Numbers', 29, 'adults', 8, 'What does the closing formula "these things ye shall do unto the LORD in your set feasts" (29:39) reveal about the theology of Israel''s worship calendar?', 'The feasts were not optional celebrations but divinely appointed sacred assemblies (mo''edim) — Israel''s worship was regulated by God''s sovereign schedule, not human preference', 'Israel could adjust the feast calendar when convenient', 'The feasts were primarily social and agricultural events', 'The formula was a later editorial addition with no theological weight', 'a', 'Numbers 29:39 — The phrase "set feasts" translates mo''edim (appointed times), established in Leviticus 23:2 — "the feasts of the LORD, even holy convocations." These were God''s appointments, not Israel''s innovations.');

-- ═══ Numbers Chapter 30 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Numbers', 30, 'kids', 1, 'When a man makes a vow to the LORD, what must he do with it?', 'He shall not break his word — he shall do according to all that proceedeth out of his mouth', 'He can change it if he wants to', 'He must tell the priest first', 'He must pay money instead', 'a', 'Numbers 30:2 — "If a man vow a vow unto the LORD, or swear an oath to bind his soul with a bond; he shall not break his word, he shall do according to all that proceedeth out of his mouth."'),
('Numbers', 30, 'kids', 2, 'If a young woman still living in her father''s house makes a vow, who has the power to allow it or stop it?', 'Her father', 'Her brother', 'The priest at the tabernacle', 'The elders of the city', 'a', 'Numbers 30:3-5 — "If a woman also vow a vow unto the LORD...and her father hear her vow...then her vows shall stand...But if her father disallow her."'),
('Numbers', 30, 'kids', 3, 'If a married woman makes a vow and her husband says nothing when he hears it, what happens to the vow?', 'It stands — the husband has confirmed it by his silence', 'It is cancelled automatically', 'She must repeat it before the priest', 'The husband must approve it in writing', 'a', 'Numbers 30:7 — "And her husband heard it, and held his peace at her in the day that he heard it: then her vows shall stand."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('Numbers', 30, 'teens', 1, 'What is the general principle established at the beginning of Numbers 30 about vows?', 'A man''s vow to the LORD is absolutely binding — he must do all that he has sworn', 'Vows could be broken if circumstances changed', 'Only priests could make binding vows', 'Vows were cancelled automatically after one year', 'a', 'Numbers 30:2 — "He shall not break his word, he shall do according to all that proceedeth out of his mouth." This principle is foundational to the integrity of Israel''s covenant relationship with God.'),
('Numbers', 30, 'teens', 2, 'If a father disallows his daughter''s vow on the day he hears it, what happens to the vow?', 'The LORD shall forgive her, because her father disallowed her', 'She must still fulfil the vow personally', 'The priest must decide if the vow stands', 'The vow is transferred to the father to fulfil', 'a', 'Numbers 30:5 — "If her father disallow her in the day that he heareth; not any of her vows, or of her bonds wherewith she hath bound her soul, shall stand: and the LORD shall forgive her."'),
('Numbers', 30, 'teens', 3, 'What happens if a husband waits and does not disallow his wife''s vow on the day he hears it?', 'He hath established her vow — he cannot disallow it afterward', 'He can disallow it at any point during the year', 'The priest must be consulted before it is final', 'The wife can cancel it herself at any time', 'a', 'Numbers 30:14 — "But if her husband altogether hold his peace at her from day to day; then he establisheth all her vows...he hath established them, because he held his peace to her in the day that he heard them."'),
('Numbers', 30, 'teens', 4, 'What is the situation of a widow or divorced woman regarding her vows?', 'Every vow she hath vowed shall stand — no man has authority over her vows', 'She must have a male guardian to validate her vows', 'Her vows are automatically cancelled', 'The elders of the city take the place of a husband for vow oversight', 'a', 'Numbers 30:9 — "But every vow of a widow, and of her that is divorced, wherewith they have bound their souls, shall stand against her."'),
('Numbers', 30, 'teens', 5, 'If a husband disallows his wife''s vow after hearing it and then changes his mind later, who bears the iniquity?', 'The husband shall bear her iniquity', 'The wife bears her own iniquity', 'Both equally bear the iniquity', 'No one bears iniquity since the vow is cancelled', 'a', 'Numbers 30:15 — "But if he shall any ways make them void after that he hath heard them; then he shall bear her iniquity."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('Numbers', 30, 'adults', 1, 'What foundational principle does Jesus build on from Numbers 30:2 in His teaching in Matthew 5:33-37?', 'Jesus radicalises the vow law — rather than requiring oaths to be kept, He commands that His disciples speak truth so consistently that oaths become unnecessary', 'Jesus cancelled all vow obligations under the new covenant', 'Jesus required more elaborate oaths than Moses', 'Jesus only addressed vows made in the temple', 'a', 'Matthew 5:37 — "Let your communication be, Yea, yea; Nay, nay." Jesus builds on the Numbers 30 principle of vow integrity, pushing it to its deepest level: integrity of character making oaths redundant.'),
('Numbers', 30, 'adults', 2, 'What theological principle underlies the authority structure of Numbers 30 regarding fathers and husbands?', 'Federal headship — the head of the household bears representative covenantal responsibility for those under his authority, including their spiritual obligations', 'Women were considered spiritually inferior in ancient Israel', 'The law was a purely pragmatic social arrangement with no theological content', 'Husbands and fathers could exploit this authority without accountability', 'a', 'Numbers 30 reflects the principle of covenantal headship (cf. 1 Corinthians 11:3, Ephesians 5:22-23) — the head bears responsibility for those under his covering, including accountability when he misuses that authority (v.15).'),
('Numbers', 30, 'adults', 3, 'What does the repeated phrase "the LORD shall forgive her" (30:5, 8, 12) reveal about God''s grace within the legal structure?', 'God provides forgiveness for obligations cancelled by legitimate authority — showing His grace operating within, not against, the legal order', 'The phrase shows that all vows were ultimately optional', 'God forgave all vows automatically', 'The phrase was a later addition to soften the law''s strictness', 'a', 'Numbers 30:5, 8, 12 — The repeated "the LORD shall forgive her" shows that when a vow is legitimately annulled by proper authority, God graciously releases the vow-maker from any guilt, demonstrating His grace working through covenant structures.'),
('Numbers', 30, 'adults', 4, 'How does Numbers 30:9 (widows'' and divorced women''s vows standing without male oversight) reflect the dignity afforded to women in the Mosaic law?', 'Women without male covering are treated as fully responsible agents — their vows are binding without any male intermediary', 'Widows and divorcees were considered less reliable than married women', 'The law showed less concern for widows'' vows than for married women''s', 'It reflected a purely practical concern about property management', 'a', 'Numbers 30:9 — A widow or divorced woman''s vow stands without any male approval, showing she is treated as a fully responsible covenant member, which is significant in an ancient Near Eastern legal context.'),
('Numbers', 30, 'adults', 5, 'What does the phrase "to bind his soul with a bond" (30:2) reveal about the Hebrew understanding of vows?', 'The Hebrew neder (vow) and issar (binding obligation) were understood as genuinely binding the soul — the inner person was ontologically committed', 'It was merely a legal metaphor with no spiritual dimension', 'Only priests could understand the spiritual nature of vows', 'Soul binding was considered dangerous and thus vows were discouraged', 'a', 'Numbers 30:2 — "To bind his soul (nephesh) with a bond (issar)." The use of nephesh shows vows engage the whole person, not merely external behaviour. Ecclesiastes 5:4-5 reinforces: "Better is it that thou shouldest not vow, than that thou shouldest vow and not pay."'),
('Numbers', 30, 'adults', 6, 'How does the vow law of Numbers 30 relate to the theology of integrity in Psalm 15:4, where the righteous man "sweareth to his own hurt, and changeth not"?', 'Both texts affirm that covenant integrity — keeping one''s sworn word even at personal cost — is a mark of true righteousness before God', 'Psalm 15 contradicts Numbers 30 by requiring all vows to be kept', 'The passages address entirely different situations', 'Psalm 15:4 is about business contracts, not religious vows', 'a', 'Psalm 15:4 — "He that sweareth to his own hurt, and changeth not." This describes the person worthy of dwelling in God''s holy hill — one whose words are as reliable as God''s own, building on the vow integrity of Numbers 30.'),
('Numbers', 30, 'adults', 7, 'What situation does Numbers 30 address regarding a woman who made a vow in her husband''s house before he heard it?', 'If her husband hears and holds his peace, the vow stands; if he disallows it on the day he hears it, the LORD shall forgive her', 'All vows made before marriage automatically transferred to the husband', 'The priest determined the validity of pre-marital vows', 'Such vows were automatically void upon marriage', 'a', 'Numbers 30:10-12 — Vows made before the husband''s knowledge: if he disallows on the day of hearing, the vow is void and she is forgiven. If he says nothing, the vow stands permanently.'),
('Numbers', 30, 'adults', 8, 'How does this chapter''s placement after the offerings calendar (Numbers 28-29) contribute to a unified theology of covenant obligation?', 'Offerings and vows together constitute the full scope of Israel''s covenantal worship — what God commands and what the worshipper voluntarily pledges must both be honoured with complete integrity', 'The chapters were placed together only by editorial accident', 'Vow law belongs in Leviticus and was misplaced in Numbers', 'The chapters address entirely separate topics with no theological connection', 'a', 'Numbers 28-30 forms a unified worship section: divinely mandated offerings (28-29) followed by voluntary vow obligations (30). Together they show that Israel''s entire devotional life — commanded and voluntary — was governed by the principle of covenant faithfulness and integrity.');
